/// Load the pre-trained GNN model with depth-9 rollout baked-in weights
pub fn load_pretrained_gnn() -> GnnEgraphModel {
    let config = GnnConfig {
        hidden_dim: 96,
        num_layers: 4,
        num_heads: 4,
        num_actions: 12,
        node_feature_dim: 33,
        learning_rate: 0.001,
        gamma: 0.99,
        num_episodes: 0,
        batch_size: 32,
        use_attention: true,
        value_loss_coef: 0.5,
        entropy_coef: 0.01,
    };
    let mut model = GnnEgraphModel::new(&config);

    // Load embedding
    model.embedding = Tensor::from_vec(EMBEDDING_WEIGHT.to_vec(), 33, 96);
    model.embedding_bias = Tensor::from_vec(EMBEDDING_BIAS.to_vec(), 1, 96);

    // Load GNN layer 0
    model.gnn_layers[0].w_self = Tensor::from_vec(GNN0_W_SELF_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[0].bias = Tensor::from_vec(GNN0_W_SELF_BIAS.to_vec(), 1, 96);
    model.gnn_layers[0].w_neigh = Tensor::from_vec(GNN0_W_NEIGH_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[0].layer_norm.gamma = Tensor::from_vec(GNN0_LN_GAMMA.to_vec(), 1, 96);
    model.gnn_layers[0].layer_norm.beta = Tensor::from_vec(GNN0_LN_BETA.to_vec(), 1, 96);
    model.gnn_layers[0].attn_key = Some(Tensor::from_vec(GNN0_ATTN_KEY.to_vec(), 96, 4));
    model.gnn_layers[0].attn_query = Some(Tensor::from_vec(GNN0_ATTN_QUERY.to_vec(), 96, 4));

    // Load GNN layer 1
    model.gnn_layers[1].w_self = Tensor::from_vec(GNN1_W_SELF_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[1].bias = Tensor::from_vec(GNN1_W_SELF_BIAS.to_vec(), 1, 96);
    model.gnn_layers[1].w_neigh = Tensor::from_vec(GNN1_W_NEIGH_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[1].layer_norm.gamma = Tensor::from_vec(GNN1_LN_GAMMA.to_vec(), 1, 96);
    model.gnn_layers[1].layer_norm.beta = Tensor::from_vec(GNN1_LN_BETA.to_vec(), 1, 96);
    model.gnn_layers[1].attn_key = Some(Tensor::from_vec(GNN1_ATTN_KEY.to_vec(), 96, 4));
    model.gnn_layers[1].attn_query = Some(Tensor::from_vec(GNN1_ATTN_QUERY.to_vec(), 96, 4));

    // Load GNN layer 2
    model.gnn_layers[2].w_self = Tensor::from_vec(GNN2_W_SELF_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[2].bias = Tensor::from_vec(GNN2_W_SELF_BIAS.to_vec(), 1, 96);
    model.gnn_layers[2].w_neigh = Tensor::from_vec(GNN2_W_NEIGH_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[2].layer_norm.gamma = Tensor::from_vec(GNN2_LN_GAMMA.to_vec(), 1, 96);
    model.gnn_layers[2].layer_norm.beta = Tensor::from_vec(GNN2_LN_BETA.to_vec(), 1, 96);
    model.gnn_layers[2].attn_key = Some(Tensor::from_vec(GNN2_ATTN_KEY.to_vec(), 96, 4));
    model.gnn_layers[2].attn_query = Some(Tensor::from_vec(GNN2_ATTN_QUERY.to_vec(), 96, 4));

    // Load GNN layer 3
    model.gnn_layers[3].w_self = Tensor::from_vec(GNN3_W_SELF_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[3].bias = Tensor::from_vec(GNN3_W_SELF_BIAS.to_vec(), 1, 96);
    model.gnn_layers[3].w_neigh = Tensor::from_vec(GNN3_W_NEIGH_WEIGHT.to_vec(), 96, 96);
    model.gnn_layers[3].layer_norm.gamma = Tensor::from_vec(GNN3_LN_GAMMA.to_vec(), 1, 96);
    model.gnn_layers[3].layer_norm.beta = Tensor::from_vec(GNN3_LN_BETA.to_vec(), 1, 96);
    model.gnn_layers[3].attn_key = Some(Tensor::from_vec(GNN3_ATTN_KEY.to_vec(), 96, 4));
    model.gnn_layers[3].attn_query = Some(Tensor::from_vec(GNN3_ATTN_QUERY.to_vec(), 96, 4));

    // Load readout
    model.readout.w = Tensor::from_vec(READOUT_W_WEIGHT.to_vec(), 96, 96);
    model.readout.b = Tensor::from_vec(READOUT_W_BIAS.to_vec(), 1, 96);

    // Load policy head
    model.policy_head.w1 = Tensor::from_vec(POLICY_W1_WEIGHT.to_vec(), 96, 96);
    model.policy_head.b1 = Tensor::from_vec(POLICY_W1_BIAS.to_vec(), 1, 96);
    model.policy_head.w2 = Tensor::from_vec(POLICY_W2_WEIGHT.to_vec(), 96, 12);
    model.policy_head.b2 = Tensor::from_vec(POLICY_W2_BIAS.to_vec(), 1, 12);

    // Load value head
    model.value_head.w1 = Tensor::from_vec(VALUE_W1_WEIGHT.to_vec(), 96, 96);
    model.value_head.b1 = Tensor::from_vec(VALUE_W1_BIAS.to_vec(), 1, 96);
    model.value_head.w2 = Tensor::from_vec(VALUE_W2_WEIGHT.to_vec(), 96, 1);
    model.value_head.b2 = Tensor::from_vec(VALUE_W2_BIAS.to_vec(), 1, 1);

    model
}